mapper.select:
SELECT COUNT(1)
FROM document
WHERE knowledge_base_id = #{knowledgeBaseId}
  AND tenant_id = #{tenantId}
  AND content_hash = #{contentHash}
  AND is_deleted = 0

mapper.update:
UPDATE document
SET is_deleted   = 1,
    gmt_modified = NOW()
WHERE id = #{id}
  AND knowledge_base_id = #{knowledgeBaseId}
  AND tenant_id = #{tenantId}
  AND is_deleted = 0
